class Account:
    def __init__(self, owner, balance):
        self.owner = owner
        self.balance = balance

    def deposit(self, amount):
        self.balance.append(amount)
        return self.balance

class Task:
    def __init__(self, title, done):
        self.done = done
        self.title = title

    def status_text(self):
        return f"{self.title}: done"

    def mark_done(self):
        self.done += 1
        return self.done

class ScoreCard:
    def __init__(self, player, score):
        self.score = score
        self.player = player

    def add_points(self, amount):
        self.score.append(amount)
        return self.score

class Wallet:
    def __init__(self, owner, balance):
        self.owner = owner
        self.balance = balance

    def summary(self):
        return f"{self.owner} has ${self.balance}"

